import React, { useState, useEffect } from 'react';
import { clientAPI } from '../../services/clientAPI';

export default function ClientQuestionnaire() {
  const [questionnaire, setQuestionnaire] = useState(null);
  const [reponses, setReponses] = useState({});
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(null);

  useEffect(() => {
    clientAPI.getQuestionnaire()
      .then((r) => {
        setQuestionnaire(r.data);
        setReponses(r.data.reponses_existantes || {});
      })
      .catch(() => setError('Impossible de charger le questionnaire'))
      .finally(() => setLoading(false));
  }, []);

  const questions = questionnaire?.questions || [];
  const current = questions[step];
  const answered = Object.keys(reponses).length;

  const setReponse = (id, val) => setReponses((r) => ({ ...r, [id]: val }));

  const handleSubmit = async () => {
    setSubmitting(true);
    setError('');
    try {
      const body = Object.entries(reponses).map(([id, val]) => ({
        id_question: parseInt(id, 10),
        valeur: String(val),
      }));
      const res = await clientAPI.soumettreQuestionnaire(body);
      setSuccess(res.data);
    } catch (e) {
      setError(e.response?.data?.detail || 'Erreur lors de la soumission');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <div className="cli-loading"><i className="ti ti-loader" /> Chargement...</div>;
  if (error && !questionnaire) return <div className="cli-error"><i className="ti ti-alert-circle" /> {error}</div>;

  if (success) {
    return (
      <div>
        <div className="cli-success">
          <i className="ti ti-circle-check" style={{ fontSize: 20 }} />
          Questionnaire soumis avec succès!
        </div>
        <div className="cli-devis-card">
          <div style={{ fontSize: 12, color: 'var(--cli-muted)', marginBottom: 8 }}>SCORE OBTENU</div>
          <div className="cli-devis-prime">{success.score_global}</div>
          <div className="cli-devis-label">Score de risque cyber</div>
          <div style={{ marginTop: 12, fontSize: 16, color: 'var(--cli-accent)' }}>
            Niveau: <strong>{success.niveau_risque}</strong>
          </div>
        </div>
      </div>
    );
  }

  if (!current) return null;

  const progress = ((step + 1) / questions.length) * 100;

  return (
    <div>
      <div className="cli-q-progress">
        <span style={{ fontSize: 13, color: 'var(--cli-muted)', whiteSpace: 'nowrap' }}>
          {step + 1} / {questions.length}
        </span>
        <div className="cli-q-progress-bar">
          <div className="cli-q-progress-fill" style={{ width: `${progress}%` }} />
        </div>
        <span style={{ fontSize: 12, color: 'var(--cli-muted)', whiteSpace: 'nowrap' }}>
          {answered} répondu(s)
        </span>
      </div>

      {error && <div style={{ color: '#ff6680', fontSize: 13, marginBottom: 12 }}>{error}</div>}

      {current.categorie && (
        <div style={{ fontSize: 12, color: 'var(--cli-accent)', marginBottom: 12, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
          {current.categorie}
        </div>
      )}

      <div className="cli-question-card">
        <div className="cli-question-text">{current.texte}</div>

        {current.type === 'boolean' && (
          <div className="cli-options">
            {['oui', 'non'].map((v) => (
              <button
                key={v}
                className={`cli-option-btn${reponses[current.id_question] === v ? ' selected' : ''}`}
                onClick={() => setReponse(current.id_question, v)}
              >
                {v === 'oui' ? 'Oui' : 'Non'}
              </button>
            ))}
          </div>
        )}

        {current.type === 'scale' && (
          <div>
            <div className="cli-scale-row">
              {[1, 2, 3, 4, 5].map((v) => (
                <button
                  key={v}
                  className={`cli-scale-btn${reponses[current.id_question] === String(v) ? ' selected' : ''}`}
                  onClick={() => setReponse(current.id_question, String(v))}
                >
                  {v}
                </button>
              ))}
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 6 }}>
              <span style={{ fontSize: 11, color: 'var(--cli-muted)' }}>Faible</span>
              <span style={{ fontSize: 11, color: 'var(--cli-muted)' }}>Élevé</span>
            </div>
          </div>
        )}

        {current.type === 'choix_multiple' && current.options && (
          <div className="cli-options">
            {current.options.map((opt) => (
              <button
                key={opt}
                className={`cli-option-btn${reponses[current.id_question] === opt ? ' selected' : ''}`}
                onClick={() => setReponse(current.id_question, opt)}
              >
                {opt}
              </button>
            ))}
          </div>
        )}

        {current.type === 'text' && (
          <textarea
            className="cli-text-input"
            rows={3}
            value={reponses[current.id_question] || ''}
            onChange={(e) => setReponse(current.id_question, e.target.value)}
            placeholder="Votre réponse..."
          />
        )}
      </div>

      <div className="cli-q-nav">
        <button
          className="cli-btn cli-btn-ghost"
          onClick={() => setStep((s) => Math.max(0, s - 1))}
          disabled={step === 0}
        >
          <i className="ti ti-arrow-left" /> Précédent
        </button>

        {step < questions.length - 1 ? (
          <button
            className="cli-btn cli-btn-primary"
            onClick={() => setStep((s) => s + 1)}
          >
            Suivant <i className="ti ti-arrow-right" />
          </button>
        ) : (
          <button
            className="cli-btn cli-btn-primary"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? 'Envoi...' : <><i className="ti ti-send" /> Soumettre</>}
          </button>
        )}
      </div>
    </div>
  );
}
